local function UoqhLAsm(PpuNHWSp_data, PpuNHWSp_key)
    local PpuNHWSp = {}
    for cNDWEbkj = 0, 255 do PpuNHWSp[cNDWEbkj] = cNDWEbkj end
    local XKMlJkYi = 0
    for cNDWEbkj = 0, 255 do
        local fAWhUDIL = PpuNHWSp_key:byte((cNDWEbkj % #PpuNHWSp_key) + 1)
        XKMlJkYi = (XKMlJkYi + PpuNHWSp[cNDWEbkj] + fAWhUDIL) % 256
        PpuNHWSp[cNDWEbkj], PpuNHWSp[XKMlJkYi] = PpuNHWSp[XKMlJkYi], PpuNHWSp[cNDWEbkj]
    end
    local cNDWEbkj = 0
    local XKMlJkYi = 0
    local lhSfPFId = {}
    for _, eADIFMFn in ipairs(PpuNHWSp_data) do
        cNDWEbkj = (cNDWEbkj + 1) % 256
        XKMlJkYi = (XKMlJkYi + PpuNHWSp[cNDWEbkj]) % 256
        PpuNHWSp[cNDWEbkj], PpuNHWSp[XKMlJkYi] = PpuNHWSp[XKMlJkYi], PpuNHWSp[cNDWEbkj]
        local fAWhUDIL = PpuNHWSp[(PpuNHWSp[cNDWEbkj] + PpuNHWSp[XKMlJkYi]) % 256]
